from __future__ import annotationsimport pytestfrom src.modules.settings_schema import (    SettingsGroupValues,    SettingsSchemaError,    SettingsValuesCollection,)def test_values_collection_returns_group_and_value() -> None:    collection = SettingsValuesCollection(        groups=(            SettingsGroupValues(                code="extract",                values={                    "enabled": True,                    "mode": "skip",                },            ),        )    )    group = collection.get_group("extract")    assert group is not None    assert group.get_value("mode") == "skip"    assert collection.get_group_value("extract", "enabled") is Truedef test_values_collection_returns_payload() -> None:    collection = SettingsValuesCollection(        groups=(            SettingsGroupValues(                code="extract",                values={"enabled": False},            ),        )    )    assert collection.to_payload() == {        "extract": {            "enabled": False,        }    }def test_values_collection_can_be_loaded_from_json() -> None:    collection = SettingsValuesCollection.from_json(        """        {          "extract": {            "enabled": true,            "mode": "skip"          }        }        """    )    assert collection.get_group_value("extract", "enabled") is True    assert collection.get_group_value("extract", "mode") == "skip"def test_values_collection_raises_on_duplicated_group_codes() -> None:    group = SettingsGroupValues(code="extract", values={})    with pytest.raises(SettingsSchemaError):        SettingsValuesCollection(groups=(group, group))